<script lang="ts">let { data, form } = $props();</script>
<section class="card no-print p-6"><p class="text-sm font-medium text-brand-600">Customers</p><h1 class="mt-2 text-3xl font-semibold text-slate-900">Manage your billing contacts</h1></section>
<section class="grid gap-6 xl:grid-cols-[0.9fr_1.1fr]"><form method="POST" action="?/create" data-testid="customer-create-form" class="card space-y-4 p-6"><h2 class="text-xl font-semibold text-slate-900">New customer</h2><p class="text-sm text-rose-600">{form?.message ?? ''}</p><input class="input" data-testid="customer-name" name="name" placeholder="Customer name" required /><input class="input" data-testid="customer-company" name="company" placeholder="Company" /><input class="input" data-testid="customer-email" name="email" type="email" placeholder="Email" /><input class="input" data-testid="customer-phone" name="phone" placeholder="Phone" /><textarea class="input min-h-28" data-testid="customer-address" name="address" placeholder="Billing address"></textarea><textarea class="input min-h-24" data-testid="customer-notes" name="notes" placeholder="Notes"></textarea><button class="btn-primary" data-testid="customer-save" type="submit">Save customer</button></form><div class="card p-6"><div class="mb-5 flex items-center justify-between"><h2 class="text-xl font-semibold text-slate-900">Customer list</h2><a class="text-sm font-medium text-brand-600" href="?archived=1">View archived</a></div>{#if data.customers.length === 0}<div data-testid="customers-empty-state" class="rounded-3xl border border-dashed border-slate-200 p-8 text-center text-sm text-slate-500">No customers yet. Add the first billing contact.</div>{:else}<div class="space-y-4">{#each data.customers as customer}<div class="rounded-3xl border border-slate-100 p-4" data-testid={`customer-card-${customer.id}`}><div class="flex flex-wrap items-start justify-between gap-4"><div><p class="font-medium text-slate-900">{customer.name}</p><p class="mt-1 text-sm text-slate-500">{customer.company || customer.email || 'No company provided'}</p></div><form method="POST" action="?/archive"><input type="hidden" name="id" value={customer.id} /><button class="btn-danger" type="submit">Archive</button></form></div><form method="POST" action="?/update" class="mt-4 grid gap-3 md:grid-cols-2"><input type="hidden" name="id" value={customer.id} /><input class="input" name="name" value={customer.name} required /><input class="input" name="company" value={customer.company} /><input class="input" name="email" type="email" value={customer.email} /><input class="input" name="phone" value={customer.phone} /><textarea class="input min-h-24 md:col-span-2" name="address">{customer.address}</textarea><textarea class="input min-h-20 md:col-span-2" name="notes">{customer.notes}</textarea><button class="btn-secondary md:w-max" data-testid={`customer-update-${customer.id}`} type="submit">Update</button></form></div>{/each}</div>{/if}</div></section>
